     1	#include "SYsULexer.hpp"
     2	#include "SYsULexer.tokens.hpp"
     3	#include <unordered_map>
     4	#include <vector>
     5	
     6	using antlr4::ParseCancellationException;
     7	using std::make_pair;
     8	
     9	namespace {
    10	
    11	using namespace SYsULexerTokens;
    12	
    13	static const std::unordered_map<std::string, size_t> kClangTokens{
    14	  { "eof", antlr4::Token::EOF },
    15	  { "int", kInt },
    16	  { "identifier", kIdentifier },
    17	  { "l_paren", kLeftParen },
    18	  { "r_paren", kRightParen },
    19	  { "return", kReturn },
    20	  { "r_brace", kRightBrace },
    21	  { "l_brace", kLeftBrace },
    22	  { "numeric_constant", kConstant },
    23	  { "semi", kSemi },
    24	  { "equal", kEqual },
    25	  { "plus", kPlus },
    26	  { "minus", kMinus },
    27	  { "comma", kComma },
    28	  { "l_square", kLeftBracket },
    29	  { "r_square", kRightBracket }
    30	};
    31	
    32	} // namespace
    33	
    34	SYsULexer::SYsULexer(antlr4::CharStream* input)
    35	  : mInput(input)
    36	  , mSource(make_pair(this, input))
    37	  , mFactory(antlr4::CommonTokenFactory::DEFAULT.get())
    38	  , mSourceName(input->getSourceName())
    39	{
    40	}
    41	
    42	std::unique_ptr<antlr4::Token>
    43	SYsULexer::nextToken()
    44	{
    45	  auto c = mInput->LA(1);
    46	  if (c == antlr4::Token::EOF) {
    47	    // 到达文件末尾，退出循环
    48	    return common_token(antlr4::Token::EOF, mInput->index(), mInput->index());
    49	  }
    50	
    51	  auto start = mInput->index();
    52	  std::string line;
    53	  while (true) {
    54	    mInput->consume();
    55	    if (c == U'\n') {
    56	      if (mInput->LA(1) == U'\r')
    57	        mInput->consume();
    58	      break;
    59	    }
    60	    if (c == U'\r') {
    61	      if (mInput->LA(1) == U'\n')
    62	        mInput->consume();
    63	      break;
    64	    }
    65	    line.push_back(c);
    66	    c = mInput->LA(1);
    67	    if (c == antlr4::Token::EOF)
    68	      return common_token(antlr4::Token::INVALID_TYPE, start, mInput->index());
    69	  }
    70	  auto stop = mInput->index();
    71	
    72	  std::size_t typeEnd, type;
    73	  std::size_t textEnd;
    74	  std::string text;
    75	
    76	  // 提取类型段
    77	  {
    78	    decltype(kClangTokens)::const_iterator typeIter;
    79	    typeEnd = line.find(' ');
    80	    if (typeEnd == std::string::npos)
    81	      goto FAIL;
    82	    typeIter = kClangTokens.find(line.substr(0, typeEnd));
    83	    if (typeIter == kClangTokens.end())
    84	      goto FAIL;
    85	    type = typeIter->second;
    86	  }
    87	
    88	  // 提取文本段
    89	  {
    90	    textEnd = line.find('\t', typeEnd + 1);
    91	    if (textEnd == std::string::npos ||
    92	        textEnd < typeEnd + 3 // 至少要有一对空引号 ''
    93	    )
    94	      goto FAIL;
    95	    text = line.substr(typeEnd + 2, textEnd - typeEnd - 3);
    96	  }
    97	
    98	  // 提取位置段
    99	  {
   100	    std::size_t locStart, locEnd, colStart, rowStart;
   101	
   102	    locStart = line.find("Loc=<", textEnd + 1);
   103	    if (locStart == std::string::npos)
   104	      goto FAIL;
   105	    locEnd = line.rfind(">");
   106	    if (locEnd == std::string::npos)
   107	      goto FAIL;
   108	    colStart = line.rfind(':', locEnd);
   109	    if (colStart == std::string::npos)
   110	      goto FAIL;
   111	    rowStart = line.rfind(':', colStart - 1);
   112	    if (rowStart == std::string::npos)
   113	      goto FAIL;
   114	
   115	    mSourceName = line.substr(locStart + 5, rowStart - locStart - 5);
   116	    mLine = std::stoul(line.substr(rowStart + 1, colStart - rowStart - 1));
   117	    mColumn = std::stoul(line.substr(colStart + 1, locEnd - colStart - 1));
   118	  }
   119	
   120	  // 解析成功
   121	  return common_token(type, start, stop, text);
   122	
   123	FAIL: // 解析失败
   124	  assert(false);
   125	}
